  ('elementary-d0d1b9a2-moex-00141', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '政府舉債係為財政及經濟上重大措施，影響國計民生甚鉅，且事涉將來需增加人民還本付息之負擔，預算 法對於政府舉債、還債與調度之規範，下列敘述何者錯誤？', '["政府歲入與歲出、債務之舉借與以前年度歲計賸餘之移用及債務之償還，均應編入其預算", "政府經常收支，應保持平衡，非因預算年度有異常情形，資本收入、公債與賒借收入及以前年度歲計賸 餘不得充經常支出之用", "政府非依法律，不得於其預算外增加債務", "其因調節短期國庫收支而發行國庫券時，依公共債務法規定辦理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:45+00:00", "source_pdf_sha1": "133c081af821", "answer_pdf_sha1": "4a9bb4d09749", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
